{"path":"data/results/dq-ad-risk-cognition-mobility-mixed.json","record_type":"result","id":"dq-ad-risk-cognition-mobility-mixed","name":"D+Q AD-risk cognition and mobility exploratory result","short_name":null,"source_title":null,"source_id":"pmid-40010154","source_ids":null,"study_id":"dq-ad-risk-cognition-mobility-pilot","outcome_id":"dq-ad-risk-cognition-mobility","finding_ids":["dq-ad-risk-pilot-cognition-mobility-signal"],"pmid":null,"summary":null,"statement":"The AD-risk pilot reported an imprecise overall MoCA increase, a larger exploratory increase among participants with lower baseline MoCA scores, and an inverse TNF-alpha/MoCA correlation after 12 weeks of intermittent D+Q.","rationale":null,"decision":null,"population":null,"population_or_model":null,"measurement_method":null,"effect":{"measure":"mean_difference","value":1,"ci_lower":-0.7,"ci_upper":2.7,"unit":"MoCA points","raw_text":"Mean MoCA increased by 1.0 point (95% CI -0.7, 2.7) overall; among participants with the lowest baseline MoCA scores, MoCA increased by 2.0 points (95% CI 0.1, 4.0). Mean TNF-alpha changed by -3.0% (95% CI -13.0, 7.1), and TNF-alpha change correlated inversely with MoCA change (r=-0.65, p=0.02)."},"caveats":["Single-arm N=12 completion sample without a control group.","Mobility endpoint values are not extracted from the abstract and need full article extraction.","Subgroup and biomarker-correlation signals are exploratory."],"endpoint_category":null,"endpoint_categories":null,"tags":["senolytics","human","pilot","cognition","mobility"]}
